# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json

inventory_db = {}
player_connections = {}

async def handle_connection(websocket, path):
    player_id = await websocket.recv()
    player_connections[player_id] = websocket
    try:
        while True:
            message = await websocket.recv()
            data = json.loads(message)
            if data['action'] == 'trade':
                sender_id = data['sender']
                receiver_id = data['receiver']
                item_id = data['item_id']

                sender_inventory = inventory_db.get(sender_id, {})
                receiver_inventory = inventory_db.get(receiver_id, {})

                if item_id in sender_inventory:
                    sender_inventory.pop(item_id)
                    receiver_inventory[item_id] = True
                    inventory_db[sender_id] = sender_inventory
                    inventory_db[receiver_id] = receiver_inventory

                    await player_connections[sender_id].send(json.dumps({'action': 'update', 'item_id': item_id, 'new_owner': receiver_id}))
                    await player_connections[receiver_id].send(json.dumps({'action': 'update', 'item_id': item_id, 'new_owner': sender_id}))
                else:
                    await websocket.send(json.dumps({'error': 'Item not found'}))
    except websockets.exceptions.ConnectionClosed:
        pass
    finally:
        del player_connections[player_id]

start_server = websockets.serve(handle_connection, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()